    11→    public function show(Task $task)
    12→    {
    13→        $this->authorize('update', $task);
    14→        $task->load([
    15→            'subtasks' => fn ($q) => $q->whereNull('parent_id')->with('children'),
    16→            'tags',
    17→        ]);
    18→        return response()->json($task);
    19→    }
